from flask import Flask, request, jsonify
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.DEBUG)
logger = logging.getLogger(__name__)

@app.before_request
def log_request_info():
    logger.debug('Headers: %s', request.headers)
    logger.debug('Body: %s', request.get_data(as_text=True))
    if 'Authorization' in request.headers:
        logger.debug('Authorization Token: %s', request.headers['Authorization'])
    return None

@app.after_request
def log_response_info(response):
    logger.debug('Response Status: %s', response.status)
    logger.debug('Response Body: %s', response.get_data(as_text=True))
    return response

@app.errorhandler(Exception)
def handle_exception(e):
    logger.error('Exception occurred: %s', e, exc_info=True)
    return jsonify(error=str(e)), 500

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    logger.debug('Login attempt for user: %s', username)
    if username == 'admin' and password == 'admin':
        return jsonify(message='Login successful'), 200
    else:
        logger.error('Failed login attempt for user: %s', username)
        return jsonify(error='Invalid credentials'), 401

if __name__ == '__main__':
    app.run(debug=True)